#include &lt;stdio.h&gt;
#include &lt;sys/ioctl.h&gt;
#include &lt;unistd.h&gt;

int main() {
    // 1. Extract the raw File Descriptor from the standard output stream
    int raw_fd = fileno(stdout);

    // 2. Prepare the destination struct specific to this ioctl command
    struct winsize w;

    // 3. Send the hardware control command to the TTY driver.
    // TIOCGWINSZ = Terminal I/O Control Get WINdow SiZe
    if (ioctl(raw_fd, TIOCGWINSZ, &w) == -1) {
        perror("ioctl failed");
        return 1;
    }

    // 4. The Kernel driver has populated the struct directly in our RAM
    printf("Terminal Size: %d rows x %d columns\n", w.ws_row, w.ws_col);
    printf("Pixel Dimensions: %d x %d\n", w.ws_ypixel, w.ws_xpixel);

    return 0;
}

#include &lt;fcntl.h&gt;
#include &lt;sys/ioctl.h&gt;
#include &lt;stdio.h&gt;

void configure_device() {
    // Engineer opens a standard configuration text file
    int fd = open("config.txt", O_RDONLY);

    struct winsize w;

    // Engineer attempts to query the terminal size
    if (ioctl(fd, TIOCGWINSZ, &w) == -1) {
        perror("Failed to get terminal size");
    }
}
